// JSON-Werkzeug. operation: format|minify|validate|query (path z.B. a.b.0.c)
async function run(input) {
  var op = String((input && input.operation) || '').toLowerCase();
  var jsonStr = (input && input.json);
  if (typeof jsonStr !== 'string') {
    try { jsonStr = JSON.stringify(jsonStr); } catch (e) { jsonStr = String(jsonStr); }
  }
  function parse() { return JSON.parse(jsonStr); }
  try {
    if (op === 'format') return { ergebnis: JSON.stringify(parse(), null, 2) };
    if (op === 'minify') return { ergebnis: JSON.stringify(parse()) };
    if (op === 'validate') {
      try { parse(); return { gueltig: true }; }
      catch (e) { return { gueltig: false, fehler: String((e && e.message) || e) }; }
    }
    if (op === 'query') {
      var p = String((input && input.path) || '');
      var obj = parse();
      var parts = p.split('.').filter(function (x) { return x.length > 0; });
      var cur = obj;
      for (var i = 0; i < parts.length; i++) {
        if (cur == null) return { fehler: 'Pfad nicht gefunden bei: ' + parts[i] };
        var key = parts[i];
        if (Array.isArray(cur) && /^\d+$/.test(key)) cur = cur[Number(key)];
        else cur = cur[key];
      }
      if (cur === undefined) return { fehler: 'Pfad nicht gefunden.' };
      return { ergebnis: cur };
    }
    return { fehler: 'Unbekannte Operation. Erlaubt: format, minify, validate, query.' };
  } catch (e) {
    return { fehler: 'Ungueltiges JSON: ' + String((e && e.message) || e) };
  }
}
